#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=200005,mod=998244353;
int n,q;
ll dp[N][4],siz[N],ans;
struct node
{
	int v;
	ll w;
};
vector<node> g[N];
void dfs1(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f) continue;
		dfs1(v,u);
		siz[u]+=siz[v];
	}
	siz[u]++;
}
void dfs2(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		ll w=g[u][i].w;
		if(v==f) continue;
		dp[v][0]=(siz[v]+1)*(n-siz[v])%mod*w*2%mod;
		dp[v][1]=siz[v]*(n-siz[v]+1)%mod*w*2%mod;
		dp[v][2]=(dp[v][0]+dp[u][2])%mod;
		dp[v][3]=(dp[v][1]+dp[u][3])%mod;
		ans=(ans+dp[v][1])%mod;
		dfs2(v,u);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<n;i++)
	{
		int u,v;
		ll w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	dfs1(1,0);
	dfs2(1,0);
	while(q--)
	{
		int k;
		ll w;
		cin>>k>>w;
		cout<<(dp[k][2]+ans-dp[k][3]+2*n*w+mod)%mod<<"\n";
	}
	return 0;
}
